                if SysMgr.hasEnvironVar(ConfigMgr.ANDCMDLIST):
                    printFunc = SysMgr.printPipe
                else:
                    printFunc = SysMgr.printStr
                printFunc(UtilMgr.convDict2Str(statusDict, pretty=False))

            SysMgr.addExitFunc(_printRes, [statusDict])

        # -------------------- COMMAND -------------------- #

        # change debuggable/profileable attribute #
        # WARN: target app should be restarted
        for t in ("SETDEBUGGABLE", "SETPROFILEABLE"):
            if not t in SysMgr.environList:
                continue
            prop = (
                "ro.debuggable" if t == "SETDEBUGGABLE" else "ro.profileable"
            )
            SysMgr.printInfo("try to set %s" % prop)
            AndroidMgr.setProp(prop, "true", True)
            sys.exit(0)

        # print package list #
        if "GETPKGLIST" in SysMgr.environList:
            # remove default output path #
            if not SysMgr.findOption("o"):
                SysMgr.outPath = None

            # get package list #
            pkgList = AndroidMgr.getPkgList(
                "INCPROC" in SysMgr.environList,
                "ONLYPROC" in SysMgr.environList,
            )

            # save list #
            if SysMgr.jsonEnable:
                statusDict["pkgList"] = pkgList
                sys.exit(0)
            elif not pkgList:
                _printErr("no package list info")
                sys.exit(0)

            # set color true string #
            ctrue = UtilMgr.convColor("true", "GREEN")

            # define getter #
            def _getVal(vv):
                if vv == "1":
                    return ctrue
                elif isinstance(vv, long):
                    return UtilMgr.convNum(vv)
                elif isinstance(vv, list):
                    return ", ".join(list(map(str, vv)))
                else:
                    return "false"

            # print list #
            for k, v in sorted(pkgList.items()):
                SysMgr.printPipe(
                    "%s: %s"
                    % (
                        k,
                        ", ".join(
                            [
                                "%s(%s)" % (vn, _getVal(vv))
                                for vn, vv in v.items()
                            ]
                        ),
                    )
                )
            sys.exit(0)

        # check unsupported command in andcmd mode #
        if not heapProf and "GETPKGLISTINFO" in SysMgr.environList:
            SysMgr.printErr("no support yet")
            sys.exit(-1)

        # check package commands #
        runPkgList = SysMgr.environList.get("RUNPKGLIST", [])
        stopPkgList = SysMgr.environList.get("STOPPKGLIST", [])
        enablePkgList = SysMgr.environList.get("ENABLEPKGLIST", [])
        disablePkgList = SysMgr.environList.get("DISABLEPKGLIST", [])
        getPkgAttr = SysMgr.environList.get("GETPKGATTR", [])
        getActList = SysMgr.environList.get("GETACTLIST", [])
        getPermList = SysMgr.environList.get("GETPERMLIST", [])
        getDumpList = SysMgr.environList.get("GETDUMPLIST", [])
        pkgList = (
            AndroidMgr.getPkgList()
            if (
                runPkgList
                or stopPkgList
                or enablePkgList
                or disablePkgList
                or getPkgAttr
                or getActList
                or getPermList
                or getDumpList
            )
            else []
        )

        # get parsing attrs #
        restr, inputMapList, mapData, color = UtilMgr.getParseMapAttr()

        # run package list #
        for p in runPkgList:
            runList = []

            # get action and data #
            p = p.rsplit("#", 2)
            data = p[2] if len(p) == 3 else None
            action = p[1] if len(p) > 1 else None
            p = p[0]

            # get activity #
            if "/" in p:
                pkg, activity = p.split("/", 1)
                runList.append([pkg, p, action, data])
            else:
                packages = [x for x in pkgList if UtilMgr.isValidStr(x, [p])]
                if not packages:
                    SysMgr.printErr("no package related to '%s" % p)
                    sys.exit(0)

                for x in packages:
                    activity = AndroidMgr.getPkgActivity(x)
                    if activity:
                        runList.append([x, activity, action, data])

            # run activity #
            for pkg, activity, action, data in runList:
                addInfo = ""
                if action:
                    addInfo += " ACTION(%s)" % action
                if data:
                    addInfo += " DATA(%s)" % data
                if addInfo:
                    addInfo = " with" + addInfo

                des = "'%s'%s" % (activity, addInfo)
                _printInfo("run " + des)

                AndroidMgr.runActivity(activity, action, data)

                if SysMgr.jsonEnable:
                    statusDict.setdefault("runPkgList", []).append(des)
        if runPkgList:
            sys.exit(0)

        # stop package list #
        processed = False
        for act, name, targetList, pkgCmd in (
            ("stop", "stopPkgList", stopPkgList, AndroidMgr.stopActivity),
            ("enable", "enablePkgList", enablePkgList, AndroidMgr.enablePkg),
            (
                "disable",
                "disablePkgList",
                disablePkgList,
                AndroidMgr.disablePkg,
            ),
        ):
            if targetList:
                processed = True

            for p in targetList:
                packages = [x for x in pkgList if UtilMgr.isValidStr(x, [p])]

                # stop package #
                for x in packages:
                    _printInfo("%s '%s'" % (act, x))
                    ret = pkgCmd(x)
                    if SysMgr.jsonEnable:
                        statusDict.setdefault(name, []).append(x)
        if processed:
            sys.exit(0)

        # get package info #
        for pname, plist in (
            ("package", getPkgAttr),
            ("activity", getActList),
            ("permission", getPermList),
            ("dump", getDumpList),
        ):
            for p in plist:
                # print info #
                targetList = [x for x in pkgList if UtilMgr.isValidStr(x, [p])]
                if not targetList:
                    _printErr("failed to get the target package")
                for x in targetList:
                    _printInfo("print '%s' %s info" % (x, pname))
                    ret = AndroidMgr.getPkgInfo(x, pname)
                    if not ret:
                        _printErr("failed to get the result")
                    elif SysMgr.jsonEnable:
                        statusDict.setdefault(pname, [])
                        statusDict[pname] += ret
                    else:
                        SysMgr.printPipe("\n".join(ret))
            if plist:
                sys.exit(0)

        # overlay list #
        overlayList = SysMgr.environList.get("OVERLAY", [])
        for t in overlayList:
            t = "" if t == "SET" else t
            _printInfo("show overlay %s" % (("'%s'" % t) if t else "list"))
            ret = AndroidMgr.getOverlayList(t)
            for x in ret:
                SysMgr.printPipe(x)
        if overlayList:
            sys.exit(0)

        # input list #
        inputList = SysMgr.environList.get("INPUT", [])
        for i in inputList:
            _printInfo("input '%s'" % i)
            AndroidMgr.injectInputEvent(i)
        if inputList:
            sys.exit(0)

        # broadcast #
        broadcastList = SysMgr.environList.get("BROADCAST", [])
        for i in broadcastList:
            _printInfo("broadcast '%s'" % i)
            AndroidMgr.broadcastIntent(i)
        if broadcastList:
            sys.exit(0)

        # content #
        contentList = SysMgr.environList.get("CONTENT", [])
        for i in contentList:
            _printInfo("content '%s'" % i)
            AndroidMgr.useContent(i)
        if contentList:
            sys.exit(0)

        # screen info #
        screenInfo = SysMgr.environList.get("SCREENINFO")
        if screenInfo:
            _printInfo("show screen info")
            AndroidMgr.printScreenInfo()
            sys.exit(0)

        # cscmd #
        cmd = SysMgr.environList.get("CSCMD")
        if cmd:
            _printInfo("run carservice command")
            cmd = None if cmd[0] == "SET" else cmd[0]
            if cmd and mapData:
                cmd = " ".join([mapData.get(c, c) for c in cmd.split(" ")])
            AndroidMgr.runCarServiceCmd(cmd)
            sys.exit(0)

        # vhalcmd #
        cmd = SysMgr.environList.get("VHALCMD")
        if cmd:
            _printInfo("run vhal command")
            cmd = None if cmd[0] == "SET" else cmd[0]
            if cmd and mapData:
                cmd = " ".join([mapData.get(c, c) for c in cmd.split(" ")])
            AndroidMgr.runVHalCmd(cmd)
            sys.exit(0)

        # -------------------- PERFETTO -------------------- #

        # check perfetto binary #
        if SysMgr.inputParam:
            binPath = None
        elif "PERFETTO" in SysMgr.environList:
            binPath = SysMgr.environList["PERFETTO"][0]
        elif not UtilMgr.which("perfetto"):
            _printErr("no found perfetto")
            return -1
        else:
            binPath = "perfetto"

        # get command #
        exe = SysMgr.getMainArgs(False) if SysMgr.hasMainArg() else None

        # make out path #
        outPath = SysMgr.makeOutPath("prof")
        if not FileAnalyzer.isValidFile(outPath, isAbs=False):
            _printErr("failed to use output path '%s'" % outPath)
            return -1

        # set java attribute #
        javaTarget = "JAVADUMP" in SysMgr.environList

        # define waiting function #
        def _waitThreshold(pids, cond, timing, target, sig=False):
            # set default handler for force termination #
            if sig:
                SysMgr.setDefaultSignal()
            else:
                SysMgr.setNormalSignal()

            # set conditions #
            origTargetCmd = None
            if "TARGETCMD" in SysMgr.environList:
                origTargetCmd = SysMgr.environList.pop("TARGETCMD")
            SysMgr.addEnvironVar("TARGETCMD", target)
            pids = SysMgr.getTids("|".join(target), isThread=False)
            if len(pids) != 1:
                _printErr(
                    (
                        "failed to monitor memory usage because "
                        "the number of target is wrong (%s)"
                    )
                    % (UtilMgr.convNum(len(pids)))
                )
                sys.exit(-1)
            pid = pids[0]

            # convert threshold #
            if cond.startswith("+"):
                rss = SysMgr.getMemStatList(pid)["rss"]
                cond = UtilMgr.convUnit2Size(cond[1:]) + rss
            else:
                cond = UtilMgr.convUnit2Size(cond)

            # wait for threshold #
            try:
                SysMgr.waitThreshold(
                    pid, rss=True, cond=cond, bt=True, purpose=timing
                )
            except SystemExit:
                sys.exit(0)
            except:
                SysMgr.printErr("canceled to wait for threshold", True)

            # recover variables #
            SysMgr.environList.pop("TARGETCMD")
            if origTargetCmd:
                SysMgr.addEnvironVar("TARGETCMD", origTargetCmd)

            # set normal handler for profiling #
            if sig:
                SysMgr.setNormalSignal()

        # system usage string #
        sysResStr = " [SYS: ?/?] "

        # do recording #
        if not SysMgr.inputParam:
            # check perfetto processes #
            pids = SysMgr.getTids("perfetto", False, True)
            if pids:
                _printWarn(
                    "%s are already running" % SysMgr.getCommList(pids), True
                )

            # send signal to heapprofd #
            if "KILLDAEMON" in SysMgr.environList:
                pids = SysMgr.getTids("heapprofd", False, True)
                if pids:
                    SysMgr.sendSignalProcs(signal.SIGKILL, pids)
                else:
                    _printErr("no heapprofd process")

            # set sample rate #
            try:
                sampleRate = SysMgr.getOption("T")
                nrSample = long(sampleRate) if sampleRate else 4096
            except SystemExit:
                sys.exit(0)
            except:
                _printErr("failed to set sampling bytes interval", True)
                return -1

            # print build type #
            _printInfo(
                "build type: [%s]" % AndroidMgr.getProp("ro.build.type")
            )

            # print selinux status #
            _printInfo("selinux status: [%s]" % AndroidMgr.getEnforce())

            # set target option #
            apps = None
            if exe and not "MEMTOP" in SysMgr.environList:
                exe = " ".join(exe)
                cmdstr = " command: [%s]" % exe
                targetstr = 'process_cmdline: "%s"' % exe
                target = exe
                memTarget = [None]
            elif "APP" in SysMgr.environList:
                convPid = "CONVPID" in SysMgr.environList

                # get pkg list #
                pkgList = AndroidMgr.getPkgList(onlyProc=convPid)

                # convert list #
                targetList = [
                    ([pi.get("pid") for pi in pv["proc"]] if convPid else pn)
                    for pn, pv in pkgList.items()
                    if UtilMgr.isValidStr(pn, SysMgr.filterGroup)
                ]
                if not targetList:
                    _printErr("failed to get app list")
                    return -1
                elif isinstance(targetList[0], list):
                    targetList = [p for x in targetList for p in x]

                # make target info #
                SysMgr.filterGroup = targetList
                apps = ",".join(SysMgr.filterGroup)
                if convPid:
                    cmdstr = " proc: [%s]" % SysMgr.getCommList(
                        SysMgr.filterGroup, cmdline=True
                    )
                else:
                    cmdstr = " app: [%s]" % apps
                targetstr = "\n".join(
                    ['process_cmdline: "%s"' % a for a in SysMgr.filterGroup]
                )
                memTarget = target = SysMgr.filterGroup
            elif SysMgr.filterGroup:
                # get pids #
                pids = []
                cmdline = "TARGETCMD" in SysMgr.environList
                for g in SysMgr.filterGroup:
                    pids += SysMgr.getTids(
                        g,
                        isThread=not SysMgr.processEnable,
                        sibling=SysMgr.groupProcEnable,
                    )
                if not pids:
                    _printErr(
                        "no task related to [%s]"
                        % ", ".join(SysMgr.filterGroup)
                    )
                    return -1

                # get comms #
                commList = SysMgr.getCommList(pids, cmdline=cmdline)
                if len(pids) > 1:
                    _printWarn("multiple tasks found [%s]" % commList, True)

                # set command #
                cmdstr = " %s: [%s]" % (
                    "process" if SysMgr.processEnable else "thread",
                    commList,
                )
                targetstr = "\n".join(["pid: " + pid for pid in pids])
                memTarget = target = pids
            else:
                cmdstr = ": [SYSTEM]"
                targetstr = "all_heaps: true"
                memTarget = target = [None]

            # print command #
            _printInfo("set target" + cmdstr)

            # print memory info #
            if "MEMTOP" in SysMgr.environList:
                # check target #
                if None in memTarget:
                    memTarget.remove(None)
                if not memTarget and not "ALLMEMTOP" in SysMgr.environList:
                    _printErr("no valid target info")
                    sys.exit(-1)

                # set interval #
                if not SysMgr.intervalEnable:
                    SysMgr.intervalEnable = 1

                # remove output path #
                if not SysMgr.findOption("o"):
                    SysMgr.outPath = None

                while 1:
                    # save timestamp #
                    prevTime = time.time()

                    AndroidMgr.saveMemDump(memTarget, True)

                    # check repeat count #
                    SysMgr.checkProgress()

                    # get delayed time #
                    delayTime = time.time() - prevTime
                    if delayTime > SysMgr.intervalEnable:
                        waitTime = 0.000001
                    else:
                        waitTime = SysMgr.intervalEnable - delayTime

                    # wait for next tick #
                    if not SysMgr.waitUserInput(waitTime):
                        time.sleep(waitTime)

                sys.exit(0)

            # change debuggable attribute #
            # WARN: target app will be restarted
            for t, cmd in (
                ("SETDEBUG", "set-debug-app"),
                ("CLEARDEBUG", "clear-debug-app"),
            ):
                for a in SysMgr.environList.get(t, []):
                    if a == "SET":
                        a = target
                    if not isinstance(a, list):
                        a = [a]
                    for i in a:
                        if not i:
                            continue
                        SysMgr.executeCommand(
                            [
                                "am %s -w %s%s"
                                % (
                                    cmd,
                                    (
                                        "--persistent "
                                        if "PERSISTENT" in SysMgr.environList
                                        else ""
                                    ),
                                    i,
                                )
                            ]
                        )

            # heapprofd config format #
            heapConfig = """
buffers {
  size_kb: 63488
}

data_sources {
  config {
    name: "android.heapprofd"
    heapprofd_config {
      shmem_size_bytes: 8388608
      sampling_interval_bytes: %s
      block_client: true
      %s

    }
  }
}

duration_ms: 0
write_into_file: true
flush_timeout_ms: 30000
flush_period_ms: 604800000
data_sources {
  config {
    name: "android.packages_list"
  }
}
            """ % (
                nrSample,
                targetstr,
            )

            # atrace config format #
            atraceConfig = """
buffers {
  size_kb: 102400
  fill_policy: RING_BUFFER
}

data_sources {
  config {
    name: "linux.ftrace"
    ftrace_config {
      # Enables specific system events tags.
      atrace_categories: "am"
      atrace_categories: "pm"

      # Enables events for a specific app.
      %s
    }
  }
}
            """ % (
                "\n".join(
                    [
                        'atrace_apps: "%s"' % aname
                        for aname in (apps.split(",") if apps else ["*"])
                    ]
                )
            )

            # java_hprof config format #
            javaConfig = """
buffers {
  size_kb: 100024
  fill_policy: DISCARD
}

data_sources {
  config {
    name: "android.java_hprof"
    java_hprof_config {
      %s

    }
  }
}

data_source_stop_timeout_ms: 100000
duration_ms: 1000
data_sources {
  config {
    name: "android.packages_list"
  }
}
            """ % (
                targetstr,
            )

            # pkglist format #
            pkgConfig = """
buffers {
  size_kb: 63488
}

duration_ms: 100
write_into_file: true
flush_timeout_ms: 30000
flush_period_ms: 604800000
data_sources {
  config {
    name: "android.packages_list"
  }
}
            """

            # procstat format #
            statConfig = """
buffers {
  size_kb: 63488
}

data_sources {
  config {
    name: "linux.process_stats"
    target_buffer: 0
    process_stats_config {
      scan_all_processes_on_start: true
      record_thread_names: true
    }
  }
}
            """

            # set config #
            term = False
            if "JAVADUMP" in SysMgr.environList:
                config = javaConfig
            elif "ATRACE" in SysMgr.environList:
                config = atraceConfig
            elif "GETPKGLISTINFO" in SysMgr.environList:
                config = pkgConfig
                term = True
            elif "GETPROCLIST" in SysMgr.environList:
                config = statConfig
                term = True
            else:
                config = heapConfig
            statusDict["javadump"] = javaTarget

            # print config #
            if SysMgr.warnEnable:
                _printWarn("[config]: " + config)
            else:
                statusDict["warn"].append(config)

            # terminate command mode #
            if not heapProf:
                SysMgr.printErr("no command option")
                sys.exit(0)

            # make default record command #
            cmd = [binPath, "--txt", "-c", "-", "-o", outPath, "-d"]
            cmd += SysMgr.environList.get("ADDRECOPT", [])

            # remove report option #
            for o in SysMgr.environList.get("RMRECOPT", []):
                if o in cmd:
                    cmd.remove(o)

            # backup an exist file #
            SysMgr.backupFile(outPath)

            # start monitoring #
            if "TASKMON" in SysMgr.environList:
                monPid = SysMgr.runTaskMonitor([""], wait=False)
            else:
                monPid = 0

            # wait for start threshold #
            startRss = SysMgr.environList.get("STARTRSS")
            if startRss:
                try:
                    _waitThreshold(pids, startRss[0], "START", target, True)
                except SystemExit:
                    sys.exit(0)
                except:
                    _printErr(
                        "failed to wait for RSS(%s) for start" % startRss[0],
                        True,
                    )
                    sys.exit(-1)

            # set timer #
            try:
                timer = SysMgr.getOption("R")
                if timer:
                    if timer.isdigit():
                        timer = long(timer)
                    else:
                        timer = UtilMgr.convTime2Sec(timer)
                    SysMgr.setSignal(signal.SIGALRM, SysMgr.alarmExitHandler)
                    signal.alarm(timer)
            except SystemExit:
                sys.exit(0)
            except:
                _printErr("failed to set timer", True)
                return -1

            # print record status #
            SysMgr.printStat(r"start profiling... [ STOP(Ctrl+c) ]")
            cmdStr = "executed '%s'" % " ".join(cmd)
            if SysMgr.warnEnable:
                SysMgr.printWarn(cmdStr)
            else:
                statusDict["warn"].append(cmdStr)
            if javaTarget:
                # set default handler for force termination #
                SysMgr.setDefaultSignal()

                SysMgr.printStat(r"wait a second...  [ STOP(Ctrl+c) ]")

            # init debugger object for system CPU usage #
            dobj = Debugger(SysMgr.pid, attach=False)
            dobj.initValues()
            startProfTime = time.time()
            dobj.getCpuUsage(system=True)

            # create a new worker process #
            subprocess = SysMgr.getPkg("subprocess")
            procObj = subprocess.Popen(
                cmd,
                stdin=subprocess.PIPE,
                stdout=subprocess.PIPE,
                stderr=None if SysMgr.warnEnable else subprocess.PIPE,
                universal_newlines=True,
                bufsize=0,
            )

            # check perfetto process #
            if not procObj:
                _printErr("failed to execute '%s'" % " ".join(cmd))
                sys.exit(0)

            # execute program #
            if exe:
                ret = SysMgr.createCmdProcess(exe, mute=True)
                if ret > 0:
                    _printInfo("executed '%s'" % exe)
                else:
                    _printErr("failed to execute '%s'" % exe)
                    sys.exit(0)

            def _waitTask(pid):
                while 1:
                    if not SysMgr.isAlive(pid):
                        break
                    else:
                        time.sleep(0.1)

            # pass config through pipe and wait #
            try:
                procObj.stdin.write(config)
                procObj.stdin.close()
                errMsg = "failed to get PID of perfetto, check SELinux mode"

                try:
                    recPid = procObj.stdout.read()
                    if not recPid:
                        raise Exception("no perfetto process")
                    recPid = long(recPid.strip())
                except SystemExit:
                    sys.exit(0)
                except:
                    recPid = 0
                    _printErr(errMsg, True)
                    return -1

                # wait for stop threshold #
                stopRss = SysMgr.environList.get("STOPRSS")
                if stopRss:
                    try:
                        _waitThreshold(pids, stopRss[0], "STOP", target)
                    except SystemExit:
                        sys.exit(0)
                    except:
                        _printErr(
                            "failed to wait for RSS(%s) for stop" % stopRss[0],
                            True,
                        )
                        sys.exit(-1)

                # wait for events #
                if javaTarget:
                    # wait for task termination #
                    _waitTask(recPid)
                elif stopRss or term:
                    pass
                else:
                    signal.pause()
            except:
                pass
            finally:
                SysMgr.repeatCnt = 0

                # send signal to perfetto process #
                if recPid and not javaTarget:
                    SysMgr.sendSignalProcs(signal.SIGINT, [recPid], verb=False)

                # check heapprofd processes #
                dlist = (
                    True
                    if (term or heapProf)
                    else SysMgr.getTids("heapprofd", False, True)
                )
                if not dlist:
                    _printWarn(
                        "no running heapprofd, check below commands", True
                    )
                    _printWarn("# setprop persist.traced.enable 1", True)
                    _printWarn(
                        "# setprop persist.traced.heapprofd.enable 1", True
                    )
                    _printWarn("# stop traced; start traced", True)

                # wait for task termination #
                if recPid:
                    _waitTask(recPid)
                else:
                    return -1

            # save system CPU usage #
            profTimeDiff = time.time() - startProfTime
            sysCpuUsage = SysMgr.getCpuUsageStr(dobj, profTimeDiff)[1]
            sysMemAvail = SysMgr.getAvailMemInfo()
            sysResStr = " [SYS: %s/%s] " % (sysCpuUsage, sysMemAvail)

            # get meminfo using dumpsys #
            AndroidMgr.saveMemDump(memTarget)

        # check record file #
        if not os.path.exists(outPath):
            _printErr("failed to find '%s'" % outPath)
            return -1

        # check KEEPRECFILE option #
        keepRec = SysMgr.hasEnvironVar(["KEEPRECFILE", "FROMSAMPLE"])

        # print dump file info #
        if not SysMgr.inputParam:
            _printInfo(
