        itemList = UtilMgr.splitString(value)
        SysMgr.ignoreItemList = UtilMgr.cleanItem(itemList)
        SysMgr.printInfo(
            "applied ignore keyword [ %s ]"
            % ", ".join(SysMgr.ignoreItemList)
        )

    elif option == "u":
        SysMgr.printOptionWarn(option, value)
        SysMgr.runBackgroundMode()

